script.body:
param([string]$RepoPath = '.', [int]$DaysStale = 30)
Push-Location $RepoPath
try {
    $cutoff = (Get-Date).AddDays(-$DaysStale)
    Write-Output "Branches not modified in the last $DaysStale days:`n"
    & git branch --format='%(refname:short)|%(committerdate:iso)' | ForEach-Object {
        $parts = $_ -split '\|'
        $branchDate = [datetime]$parts[1]
        if ($branchDate -lt $cutoff) {
            [PSCustomObject]@{
                Branch = $parts[0]
                LastCommit = $branchDate.ToString('yyyy-MM-dd')
                DaysOld = [math]::Floor(((Get-Date) - $branchDate).TotalDays)
            }
        }
    } | Sort-Object DaysOld -Descending | Format-Table -AutoSize
} finally {
    Pop-Location
}
